def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, capacity in enumerate(bins):
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        usage_ratio = item / capacity
        base_priority = 75 + (capacity ** 0.5) * 5
        priority = base_priority
        if usage_ratio > 3:
            multiplier = 4000 * np.power(usage_ratio, 1.3)
            priority += multiplier
            if capacity > 7:
                priority += 120 * np.log1p(capacity) * np.sin(capacity)
            else:
                priority -= 30 * usage_ratio ** 1.2
            for a in range(1, 4):
                priority += ((-1) ** a) * np.cos(usage_ratio * np.pi * a * 0.5) * (50 / a)
        elif 2 < usage_ratio <= 3:
            delta = usage_ratio - 2
            priority += 1500 * delta ** 1.5 + 80 * (1 - delta)
            for b in range(1, 7):
                priority += ((-1) ** b) * np.sin(usage_ratio * np.e * b) * (20 / b)
                if b % 2 == 0:
                    priority -= b * 3 * np.exp(-usage_ratio)
            if capacity % 2 < 0.25:
                priority += 30 * np.cos(capacity * 2.5)
        elif 0.8 < usage_ratio <= 2:
            try:
                log_val = np.log1p(1 - usage_ratio + 1e-16)
                priority += (-log_val) ** 3 * 20
            except FloatingPointError:
                priority += 200
            for c in range(1, 10):
                power = usage_ratio ** c
                if power < 0.4:
                    priority += power * 22 / c
                    if c % 4 == 0:
                        priority += 3 * c
                else:
                    priority += (1 - power) * 18 / (c + 1)
                    if c == 7 and usage_ratio > 1.1:
                        priority += 12
            if capacity % 2.5 < 0.4:
                priority += 25 * np.sin(capacity * 4)
            for d in range(1, 5):
                priority += (np.tan(usage_ratio * np.pi / (d + 2)) - 0.6) * 15 / d
        else:
            priority += 120 * (1 - usage_ratio) ** 2
            for e in range(1, 8):
                ratio_pow = usage_ratio ** e
                priority += (np.tan(ratio_pow * np.pi / 3) - 0.4) * 20 / e
                if usage_ratio < 0.08 * e:
                    priority -= 8 * e
            if capacity < 0.03:
                priority += np.sqrt(capacity) * 300
                priority -= 25 * np.exp(-capacity * 50)
            elif capacity < 0.6:
                priority += np.log1p(capacity * 15) * 40
            else:
                priority += (capacity % 4) * 18
            if capacity % 1 < 0.1 and usage_ratio < 0.5:
                priority -= 30
        if capacity < 0.15:
            priority += 55
            if usage_ratio > 0.9:
                priority += 70
            elif usage_ratio < 0.1:
                priority -= 50
                for f in range(1, 5):
                    priority -= f * np.exp(-usage_ratio * 12)
        elif capacity < 1.0:
            priority += 30
            if usage_ratio > 0.9:
                priority += 55
            elif usage_ratio < 0.35:
                priority -= 20
            for g in range(1, 4):
                priority += (-1) ** g * np.sin(capacity * g * np.pi) * 7
        else:
            if usage_ratio < 0.15:
                priority -= 35
                for h in range(1, 6):
                    priority -= h * np.cos(usage_ratio * h * np.pi * 2)
            elif usage_ratio > 0.9:
                priority += 75
                for i_ in range(1, 4):
                    priority += i_ * np.exp(-usage_ratio * i_ * 5)
            else:
                priority += 30
        proximity_score = 0
        if int(capacity * 1500) % 17 == 0:
            proximity_score += 15
        if int(capacity * 700) % 13 == 0:
            proximity_score -= 10
        if int(capacity * 200) % 7 == 0:
            proximity_score += 12
        for k in range(1, 8):
            diff = abs(usage_ratio - k / 8)
            if diff < 0.025:
                proximity_score += 20 / k
            elif diff < 0.06:
                proximity_score += 12 / k
            else:
                proximity_score -= 3 / k
        for m in range(2, 8):
            mod_check = int(capacity * 1500) % (m + 6)
            if mod_check == 0:
                proximity_score += m * 4
            elif mod_check == 2:
                proximity_score -= m * 3
        for n in range(1, 5):
            mod_check = int(usage_ratio * 1500) % (n + 4)
            if mod_check == 0:
                proximity_score += 8 * n
            elif mod_check == 1:
                proximity_score -= 6 * n
        priority += proximity_score
        if usage_ratio < 0.01:
            for s in range(1, 6):
                priority -= s * 7
        elif usage_ratio > 0.97:
            for t in range(1, 6):
                priority += t * 8
        if capacity > 2:
            if capacity % 1 < 0.03:
                priority += 35
            if (int(capacity * 1500) % 19 == 0) and (usage_ratio > 0.55):
                priority += 50
            if capacity % 0.5 < 0.07:
                priority += 20 * np.sin(capacity * 10)
        if abs(priority) > 1.5e4:
            priority = np.sign(priority) * 1.5e4
        priorities[i] = priority
    return priorities
